def ecdf(data):
    """Compute ECDF for a one-dimensional array of measurements."""
    n = len(data)
    x = np.sort(data)
    y = np.arange(1, n + 1) / n
    return (x, y)

def apply_ecdf(eval_data, ecdf_x, ecdf_y):
    """Apply the ECDF to an evaluation array."""
    result = []
    for value in eval_data:
        idx = np.searchsorted(ecdf_x, value, side='right')
        if idx == 0:
            result.append(0)
        else:
            result.append(ecdf_y[idx - 1])
    return np.array(result)
(grades_ecdf_x, grades_ecdf_y) = ecdf(grades)
